ALTER TABLE "answer_record" ADD COLUMN "practice_attempt_number" integer;--> statement-breakpoint
ALTER TABLE "answer_record" ADD COLUMN "practice_max_attempt_count" integer;--> statement-breakpoint
CREATE UNIQUE INDEX "udx_answer_record_practice_question_attempt" ON "answer_record" USING btree ("practice_id","paper_question_public_id","practice_attempt_number") WHERE "answer_record"."practice_attempt_number" is not null;--> statement-breakpoint
CREATE UNIQUE INDEX "udx_mistake_book_user_id_question_public_id" ON "mistake_book" USING btree ("user_id","question_public_id");--> statement-breakpoint
ALTER TABLE "answer_record" ADD CONSTRAINT "chk_answer_record_practice_attempt_completeness" CHECK (("answer_record"."practice_attempt_number" is null and "answer_record"."practice_max_attempt_count" is null) or ("answer_record"."practice_attempt_number" is not null and "answer_record"."practice_max_attempt_count" is not null));--> statement-breakpoint
ALTER TABLE "answer_record" ADD CONSTRAINT "chk_answer_record_practice_attempt_mode" CHECK ("answer_record"."practice_attempt_number" is null or ("answer_record"."exam_mode" = 'practice' and "answer_record"."practice_id" is not null and "answer_record"."mock_exam_id" is null));--> statement-breakpoint
ALTER TABLE "answer_record" ADD CONSTRAINT "chk_answer_record_practice_attempt_bounds" CHECK ("answer_record"."practice_attempt_number" is null or ("answer_record"."practice_attempt_number" >= 1 and "answer_record"."practice_attempt_number" <= "answer_record"."practice_max_attempt_count" and "answer_record"."practice_max_attempt_count" in (1, 2)));